import {
  type ReactNode,
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
} from 'react';
import './list.scss';
import { ListContext } from './list_context';

interface ListProps {
  children: ReactNode;
  itemCount: number;
  onActiveIndexChange?: (index: number) => void;
  onAction?: (index: number) => void;
  detail?: ReactNode;
}

export function List({
  children,
  itemCount,
