      { label: 'Quarters', value: 'quarters' },
      { label: 'Other', value: 'other' },
    ],
  },
];

export function WindowManagementView() {
  const nav = useNavigation();
  const [query, setQuery] = useState('');
  const [filterValue, setFilterValue] = useState('all');
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [actionsOpen, setActionsOpen] = useState(false);
  const { items: hudItems, show: showHUD } = useHUD();

  const filtered = useMemo(() => {
    let items = WINDOW_LAYOUTS;
    if (filterValue !== 'all') {
      items = items.filter(l => l.category === filterValue);
    }
    if (query) {
      items = items.filter(l => fuzzyMatch(query, l.name));
    }
    return items;
  }, [query, filterValue]);

  const groupedByCategory = useMemo(() => {
    const groups: { category: LayoutCategory; items: typeof filtered }[] = [];
    const seen = new Set<LayoutCategory>();
    for (const item of filtered) {
      if (!seen.has(item.category)) {
        seen.add(item.category);
        groups.push({
          category: item.category,
          items: filtered.filter(l => l.category === item.category),
        });
      }
    }
    return groups;
  }, [filtered]);

  const flatItems = useMemo(() => filtered, [filtered]);
  const totalItemCount = flatItems.length;

  const selectedLayout = flatItems[selectedIndex];

  const handleQueryChange = useCallback((value: string) => {
    setQuery(value);
    setSelectedIndex(0);
    setActionsOpen(false);
  }, []);

  const handleFilterChange = useCallback((value: string) => {
    setFilterValue(value);
    setSelectedIndex(0);
  }, []);

  const handleActiveIndexChange = useCallback((index: number) => {
    setSelectedIndex(index);
    setActionsOpen(false);
  }, []);

  const handleApply = useCallback(() => {
    if (!selectedLayout) return;
    setActionsOpen(false);
    showHUD({
      icon: <ApplyHUDIcon />,
      title: `Applied ${selectedLayout.name}`,
    });
  }, [selectedLayout, showHUD]);

  const handleCopyName = useCallback(() => {
    if (!selectedLayout) return;
    setActionsOpen(false);
    performCopy(selectedLayout.name, showHUD);
  }, [selectedLayout, showHUD]);

  const toggleActions = useCallback(() => {
    setActionsOpen(prev => !prev);
  }, []);

  const closeActions = useCallback(() => {
    setActionsOpen(false);
  }, []);

  useKeyboardShortcut({ key: 'k', meta: true }, toggleActions);
  useKeyboardShortcut({ key: 'c', meta: true }, handleCopyName);

  const dropdownSections: DropdownSection[] = useMemo(
    () => [
      {
        title: 'Actions',
        actions: [
          {
            label: 'Apply Layout',
            shortcut: <Kbd keys={['↵']} />,
            onClick: handleApply,
          },
          createCopyAction(
            {
              content: selectedLayout?.name ?? '',
              title: 'Copy Name',
              shortcut: <Kbd keys={['⌘', 'C']} />,
            },
            showHUD,
          ),
        ],
      },
    ],
    [selectedLayout?.name, handleApply, showHUD],
  );

  const activeDescendantId =
    totalItemCount > 0 ? `list-item-${selectedIndex}` : undefined;

  function renderLayoutItem(
    layout: (typeof WINDOW_LAYOUTS)[number],
    idx: number,
  ): ReactNode {
    return (
      <ListItem
        key={layout.id}
        index={idx}
        icon={getLayoutIcon(layout)}
        title={layout.name}
        accessories={[
          {
            tag: {
              text: CATEGORY_LABELS[layout.category],
              color:
                layout.category === 'halves'
                  ? 'blue'
                  : layout.category === 'thirds'
                    ? 'green'
                    : layout.category === 'quarters'
                      ? 'orange'
                      : 'purple',
            },
          },
          {
            icon: <Kbd keys={layout.shortcutKeys} />,
          },
        ]}
        query={query || undefined}
      />
    );
  }

  return (
    <>
      <SearchBar
        value={query}
        onChange={handleQueryChange}
        placeholder="Search Layouts..."
        activeDescendantId={activeDescendantId}
        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
        dropdown={
          <SearchDropdown
            sections={FILTER_SECTIONS}
            value={filterValue}
            onChange={handleFilterChange}
          />
        }
      />
      <div className="command-palette__body">
        <div className="command-palette__list-container">
          {totalItemCount === 0 ? (
            <EmptyState
              icon={<SearchEmptyIcon />}
              title="No Layouts Found"
              description="Try a different search term or filter"
            />
          ) : (
            <List
              itemCount={totalItemCount}
              onActiveIndexChange={handleActiveIndexChange}
              onAction={handleApply}
            >
              {(() => {
                let globalIndex = 0;
                return groupedByCategory.map(group => (
                  <ListSection
                    key={group.category}
                    title={CATEGORY_LABELS[group.category]}
                  >
                    {group.items.map(layout =>
                      renderLayoutItem(layout, globalIndex++),
                    )}
                  </ListSection>
                ));
              })()}
            </List>
          )}
        </div>
      </div>
      <ActionPanel
        contextLabel="Window Management"
        actions={[
          {
            label: 'Apply Layout',
            shortcut: <Kbd keys={['↵']} />,
          },
          {
            label: 'Actions',
            shortcut: <Kbd keys={['⌘', 'K']} />,
            onClick: toggleActions,
          },
        ]}
        dropdownOpen={actionsOpen}
        dropdownSections={dropdownSections}
        onDropdownClose={closeActions}
      />
      <HUDContainer items={hudItems} />
    </>
  );
}

